API_name: nchu_course_search_by_sdg
Description:
{
  "description": "Search courses by UN Sustainable Development Goals (SDGs). JSON string containing courses related to the specified SDG",
  "required_parameters": [
    {
      "name": "sdg_keyword",
      "type": "STRING",
      "description": "SDG keyword to search for (e.g., 氣候, 永續, 健康, 教育)"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "Maximum number of results to return (default: 20)",
      "default": 20
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

